{
  "sentences": [
    {
      "text": "你好，我想要一杯拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a latte, okay?",
      "translation_ko": "안녕하세요, 라떼 한 잔 주세요, 괜찮나요?"
    },
    {
      "text": "可以幫我加珍珠嗎？",
      "pinyin": "Kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Can you add boba for me?",
      "translation_ko": "타피오카 펄을 넣어 주시겠어요?"
    },
    {
      "text": "我要一杯小杯紅茶，半糖，可以嗎？",
      "pinyin": "Wǒ yào yī bēi xiǎo bēi hóngchá, bàn táng, kěyǐ ma?",
      "pinyin_numeric": "wo3 yao4 yi1 bei1 xiao3 bei1 hong2cha2, ban4 tang2, ke3yi3 ma0?",
      "translation_en": "I want a small black tea, half sugar, okay?",
      "translation_ko": "작은 컵 홍차 반 당으로 주세요, 괜찮나요?"
    },
    {
      "text": "可以給我一個袋子嗎？",
      "pinyin": "Kěyǐ gěi wǒ yī gè dàizi ma?",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 ge4 dai4zi ma0?",
      "translation_en": "Can you give me a bag?",
      "translation_ko": "봉투 하나 주시겠어요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì ma?",
      "pinyin_numeric": "bu4 hao3 yi4si, ke3yi3 zai4 shuo1 yi1 ci4 ma0?",
      "translation_en": "Excuse me, can you say that again?",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요?"
    },
    {
      "text": "可以幫我外帶嗎？",
      "pinyin": "Kěyǐ bāng wǒ wàidài ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 wai4dai4 ma0?",
      "translation_en": "Can you make it to go for me?",
      "translation_ko": "포장해 주시겠어요?"
    },
    {
      "text": "我要一杯冰拿鐵，少冰，可以嗎？",
      "pinyin": "Wǒ yào yī bēi bīng nátiě, shǎo bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 yao4 yi1 bei1 bing1 na2tie3, shao3 bing1, ke3yi3 ma0?",
      "translation_en": "I want an iced latte, less ice, okay?",
      "translation_ko": "얼음 라떼 적게 얼음으로 주세요, 괜찮나요?"
    },
    {
      "text": "可以給我一根吸管嗎？",
      "pinyin": "Kěyǐ gěi wǒ yī gēn xīguǎn ma?",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 gen1 xi1guan3 ma0?",
      "translation_en": "Can you give me a straw?",
      "translation_ko": "빨대 하나 주시겠어요?"
    },
    {
      "text": "麻煩你，可以慢一點說嗎？",
      "pinyin": "Máfan nǐ, kěyǐ màn yīdiǎn shuō ma?",
      "pinyin_numeric": "ma2fan ni3, ke3yi3 man4 yi1dian3 shuo1 ma0?",
      "translation_en": "Excuse me, can you speak a little slower?",
      "translation_ko": "죄송합니다, 조금 천천히 말씀해 주시겠어요?"
    },
    {
      "text": "我想要一杯豆漿，內用，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dòujiāng, nèiyòng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4jiang1, nei4yong4, ke3yi3 ma0?",
      "translation_en": "I would like a cup of soy milk, for here, okay?",
      "translation_ko": "두유 한 잔 매장에서 먹을게요, 괜찮나요?"
    }
  ]
}
